from vex import Guardrail, Policy

guardrail = Guardrail()
guardrail.add_metric('thread_tokens', threshold=120000, action='summarize')

def token_middleware(agent_session):
    tokens = agent_session.thread.token_count
    if guardrail.check_metric('thread_tokens', tokens):
        summary = agent_session.summarize_thread()
        agent_session.new_thread(summary)
        return {'status': 'degraded', 'new_thread_id': agent_session.thread.id}
    return {'status': 'ok'}

import { Guardrail, Policy } from '@vex/sdk';

const policy = new Policy('pci_dss_payments');
policy.addRule('tokenization_required', (input: any) => {
  return input.cardNumber?.startsWith('****') || input.paymentMethod === 'token';
});
policy.addRule('no_pii_logging', (input: any) => {
  return !input.includes('cardNumber') && !input.includes('cvv');
});

const guardrail = new Guardrail(policy);

export async function azurePaymentMiddleware(toolCall: any): Promise<any> {
  if (toolCall.name === 'process_payment') {
    const validation = await guardrail.validate(toolCall.parameters);
    if (!validation.passed) {
      throw new Error(`PCI violation: ${validation.violations.join(', ')}`);
    }
  }
  // Forward to Azure AI Agent
  return await agentSession.callTool(toolCall);
}

